import React from 'react';
export default function ContactPage() {
  return (
    <div style={{ paddingTop:'var(--nav-h)', minHeight:'80vh', maxWidth:'var(--max-w)', margin:'0 auto', padding:'60px 24px' }}>
      <h1 style={{ fontFamily:'var(--ff-display)', fontSize:40, fontWeight:400, marginBottom:16 }}>Contact</h1>
      <p style={{ color:'var(--warm-gray)' }}>Full Contact page — implement using the design patterns from the interactive demo above.</p>
    </div>
  );
}
